info:
异构终端节点互通示例：
- 订阅 telemetry/+/+，分别缓存最近一次 wifi/ble 节点的 device_id
- BLE 节点变暗 -> 给 Wi-Fi (ESP32) 发 {"led":"yellow"}
- Wi-Fi 节点温度 > 28°C -> 给 BLE (STM32) 发 {"beep":3}
- 命令通过 smarthome/v1/command/<type>/<id> 发布，由网关转换到对应物理协议

func:
// 把最近一次见到的同类型 device_id 写入 flow.context
// 这样从 BLE 触发时能查到最近活跃的 wifi 节点（反之亦然）
const p = msg.payload || {};
const t = p.device_type;
const id = p.device_id;
if (t && id) {
  flow.set('last_id_' + t, id);
  flow.set('last_seen_' + t, Date.now());
}
return msg;

// Wi-Fi 节点温度高 -> 给最近活跃的 BLE 节点发蜂鸣命令；带回 src_seq 便于测试脚本配对
const peer = flow.get('last_id_ble');
if (!peer) {
  node.warn('no BLE peer cached, skip');
  return null;
}
const src = msg.payload.device_id;
const srcSeq = (msg.payload && msg.payload.payload && msg.payload.payload.seq);
return {
  topic: `smarthome/v1/command/ble/${peer}`,
  payload: { beep: 3, reason: 'wifi_temp_high', src: src, src_seq: srcSeq, ts: Date.now() }
};

const p = (msg.payload && msg.payload.payload) || {};
const light = p.light !== undefined ? p.light : p.l;
const dark  = (p.dark === true) || (p.d === 1) || (typeof light === 'number' && light < 100);
return dark ? msg : null;

// BLE 节点变暗 -> 给最近活跃的 Wi-Fi (ESP32) 节点亮黄灯；带回 src_seq 便于测试脚本配对
const peer = flow.get('last_id_wifi');
if (!peer) {
  node.warn('no Wi-Fi peer cached, skip');
  return null;
}
const src = msg.payload.device_id;
const srcSeq = (msg.payload && msg.payload.payload && msg.payload.payload.seq);
return {
  topic: `smarthome/v1/command/wifi/${peer}`,
  payload: { led: 'yellow', reason: 'ble_dark', src: src, src_seq: srcSeq, ts: Date.now() }
};
